mapper.select:
        select reqid, aprvlineid, seq, stepname, status, approverid, approvername, DATE_FORMAT(regdate,'%Y/%m/%d %H:%i:%s') as regdate, comment
		  from cotdl.tbl_piiapprovalstepreq a
          where reqid= #{reqid, jdbcType=VARCHAR}

mapper.delete:
		delete from cotdl.tbl_piiapprovalstepreq 
		 where reqid = #{reqid, jdbcType=VARCHAR}
           and aprvlineid = #{aprvlineid, jdbcType=VARCHAR}
           and seq = #{seq, jdbcType=VARCHAR}

mapper.update:
		update cotdl.tbl_piiapprovalstepreq
		set 
			phase= #{phase, jdbcType=VARCHAR},
			upddate = NOW()
		where reqid = #{reqid, jdbcType=VARCHAR}
		  and aprvlineid = #{aprvlineid, jdbcType=VARCHAR}
		  and seq = #{seq, jdbcType=VARCHAR}

mapper.select:
 
		 
		select
			reqid, aprvlineid, seq, stepname, status, approverid, approvername, regdate, comment
		from (
					 select a.reqid, a.aprvlineid, a.seq, a.stepname, a.status, a.approverid, a.approvername, DATE_FORMAT(a.regdate,'%Y/%m/%d %H:%i:%s') as regdate, a.comment
					 from cotdl.tbl_piiapprovalstepreq a
				) as f
		
	    
		order by reqid desc, aprvlineid, seq
			limit #{offset}, #{amount}
